const runs = $input.all().map(item => item.json);

if (runs.length === 0) {
  throw new Error("No completed ingestion runs were found.");
}

runs.sort((a, b) => {
  return new Date(b.completed_at || b.started_at) -
    new Date(a.completed_at || a.started_at);
});

const latestRun = runs[0];

return [
  {
    json: {
      analysis_request:
        $('When Executed by Another Workflow')
          .first()
          .json
          .analysis_request,

      run_id: latestRun.id,
      completed_at: latestRun.completed_at,
      raw_record_count: latestRun.raw_record_count,
      relevant_record_count:
        latestRun.relevant_record_count,
      total_stored: latestRun.total_stored
    }
  }
];

const reviews = $input.all().map(item => item.json);
const latestRun = $('Select Latest Run').first().json;

const discoveryReviews = reviews.filter(
  review => review.is_discovery_related === true
);

function countBy(items, field) {
  return items.reduce((counts, item) => {
    const value = item[field] || "unknown";
    counts[value] = (counts[value] || 0) + 1;
    return counts;
  }, {});
}

function percentage(count, total) {
  if (!total) return 0;
  return Number(((count / total) * 100).toFixed(1));
}

const sourceCounts = countBy(reviews, "source");
const discoveryBySource = countBy(
  discoveryReviews,
  "source"
);

const themeCounts = countBy(
  discoveryReviews,
  "primary_theme"
);

const sentimentCounts = countBy(
  discoveryReviews,
  "sentiment"
);

const severityCounts = countBy(
  discoveryReviews,
  "severity"
);

const segmentCounts = countBy(
  discoveryReviews,
  "user_segment"
);

const sourceBreakdown = {};

for (const source of Object.keys(sourceCounts)) {
  const total = sourceCounts[source];
  const relevant = discoveryBySource[source] || 0;

  sourceBreakdown[source] = {
    total_records: total,
    discovery_related_records: relevant,
    discovery_related_percentage:
      percentage(relevant, total)
  };
}

const topThemes = Object.entries(themeCounts)
  .map(([theme, count]) => ({
    theme,
    count,
    percentage_of_discovery_records:
      percentage(count, discoveryReviews.length)
  }))
  .sort((a, b) => b.count - a.count);

return [
  {
    json: {
      analysis_request:
        latestRun.analysis_request || null,

      run: {
        run_id: latestRun.run_id,
        completed_at: latestRun.completed_at,
        raw_record_count:
          latestRun.raw_record_count,
        total_stored:
          latestRun.total_stored
      },

      overview: {
        total_reviews: reviews.length,
        classified_reviews: reviews.filter(
          review =>
            review.is_discovery_related !== null &&
            review.is_discovery_related !== undefined
        ).length,
        discovery_related_reviews:
          discoveryReviews.length,
        discovery_related_percentage:
          percentage(
            discoveryReviews.length,
            reviews.length
          )
      },

      source_breakdown: sourceBreakdown,
      top_themes: topThemes,
      theme_counts: themeCounts,
      sentiment_counts: sentimentCounts,
      severity_counts: severityCounts,
      behavioral_segment_counts: segmentCounts
    }
  }
];
